createLocation.query:
#graphql
  #graphql
  fragment LocationLifecycleFields on Location {
    id
    name
    isActive
    activatable
    deactivatable
    fulfillsOnlineOrders
    hasActiveInventory
    hasUnfulfilledOrders
    deletable
    shipsInventory
  }


  mutation LocationLifecycleFixtureAdd($input: LocationAddInput!) {
    locationAdd(input: $input) {
      location {
        ...LocationLifecycleFields
      }
      userErrors {
        field
        message
      }
    }
  }

hydrateLocation.query:
#graphql
  query StorePropertiesLocationHydrate($id: ID!) {
    location(id: $id) {
      id
      legacyResourceId
      name
      activatable
      addressVerified
      createdAt
      deactivatable
      deactivatedAt
      deletable
      fulfillsOnlineOrders
      hasActiveInventory
      hasUnfulfilledOrders
      isActive
      isFulfillmentService
      shipsInventory
      updatedAt
      fulfillmentService {
        id
        handle
        serviceName
      }
      address {
        address1
        address2
        city
        country
        countryCode
        formatted
        latitude
        longitude
        phone
        province
        provinceCode
        zip
      }
      suggestedAddresses {
        address1
        countryCode
        formatted
      }
      metafield(namespace: "custom", key: "hours") {
        id
        namespace
        key
        value
        type
      }
      metafields(first: 3) {
        nodes {
          id
          namespace
          key
          value
          type
        }
        pageInfo {
          hasNextPage
          hasPreviousPage
          startCursor
          endCursor
        }
      }
      inventoryLevels(first: 3) {
        nodes {
          id
          item {
            id
          }
          location {
            id
            name
          }
          quantities(names: ["available", "committed", "on_hand"]) {
            name
            quantity
            updatedAt
          }
        }
        pageInfo {
          hasNextPage
          hasPreviousPage
          startCursor
          endCursor
        }
      }
    }
  }

